// Process ALL VAPI responses instead of just first one
const allResponses = $input.all();
return allResponses.map((item, index) => {
  const vapiResponse = item.json;

  console.log(`=== VAPI RESPONSE ${index + 1} ===`);
  console.log(JSON.stringify(vapiResponse, null, 2));

  let callId = vapiResponse.id || vapiResponse.callId || vapiResponse.call_id;

  if (!callId) {
    throw new Error('Failed to get call ID from VAPI response. Full response: ' + JSON.stringify(vapiResponse));
  }

  // Validate UUID format
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(callId)) {
    throw new Error('Call ID is not a valid UUID: ' + callId);
  }

  console.log('Valid Call ID extracted:', callId);

  // Get corresponding customer data from "Process Customer Data1" node
  const customerData = $('Process Customer Data1').all()[index].json;

  return {
    json: {
      callId: callId,
      callStatus: vapiResponse.status || 'initiated',
      customerName: customerData.name,
      customerPhone: customerData.phone,
      customerEmail: customerData.email,
      customerId: customerData.id,  // Database ID
      callStartTime: new Date().toISOString()
    }
  };
});

const inputData = $input.all();
const customers = inputData[0].json.data;

return customers
  .filter(customer => {
    if (!customer.phone) return false;
    let phone = customer.phone.trim();
    return phone.length > 0;
  })
  .map(customer => {
    let phone = customer.phone.trim();

    if (!phone.startsWith('+')) {
      phone = '+' + phone;
    }

    return {
      json: {
        id: customer.id,
        name: customer.name,
        phone: phone,
        email: customer.email,
        status: customer.status,
        call_id: customer.call_id,
        recording: customer.recording
      }
    };
  });

// Get calling customers from previous node
const apiResponse = $input.first().json;
const callingCustomers = apiResponse.data || apiResponse || [];

console.log('Currently calling:', callingCustomers.length);

// Calculate available slots
const MAX_CONCURRENT = 10;
const availableSlots = Math.max(0, MAX_CONCURRENT - callingCustomers.length);

console.log('Available slots:', availableSlots);

// If no slots available, stop workflow
if (availableSlots === 0) {
  console.log('All 10 slots occupied - stopping workflow');
  return [];
}

// Pass available slots to next node
return [{
  json: {
    availableSlots: availableSlots,
    currentlyCalling: callingCustomers.length
  }
}];

const items = $input.all();

return items.map(item => {
  const data = item.json;
  const summary = data.summary || '';

  // Handle null or "null" string summaries
  if (summary === 'null' || summary === '' || !summary) {
    return {
      json: {
        callId: data.callId,
        meetingAccepted: false,
        childName: 'Not confirmed',
        parentName: 'Not confirmed',
        phone: 'Not confirmed',
        email: 'Not confirmed',
        timezone: 'Not confirmed',
        appointmentDateTime: 'Not confirmed',
        childGrade: 'Not confirmed',
        subject: 'Not confirmed'
      }
    };
  }

  // Helper function to extract field value from structured section
  const extractField = (text, fieldName) => {
    const regex = new RegExp(`${fieldName}:\\s*(.+?)(?:\\n|$)`, 'i');
    const match = text.match(regex);
    return match ? match[1].trim() : 'Not confirmed';
  };

  // Extract structured fields from the formatted sections
  const appointmentBooked = extractField(summary, 'Booked');
  const meetingAccepted = appointmentBooked.toLowerCase().includes('yes');

  // Extract appointment time and date
  const appointmentTime = extractField(summary, 'Time');
  const appointmentDate = extractField(summary, 'Date');
  const appointmentDateTime = (appointmentTime !== 'Not confirmed' || appointmentDate !== 'Not confirmed') 
    ? `${appointmentDate} at ${appointmentTime}`.replace('Not confirmed at ', '').replace(' at Not confirmed', '')
    : 'Not confirmed';

  // Extract customer info
  const parentName = extractField(summary, 'Name');
  const email = extractField(summary, 'Email');
  const phone = extractField(summary, 'Phone');
  const timezone = extractField(summary, 'Timezone');

  // Extract child info
  const childName = extractField(summary, 'Child Name');
  const childGradeRaw = extractField(summary, 'Grade');

  // Extract only the numeric value from grade
  let childGrade = null;
  if (childGradeRaw !== 'Not confirmed') {
    const gradeMatch = childGradeRaw.match(/\d+/);
    if (gradeMatch) {
      childGrade = parseInt(gradeMatch[0], 10);
    }
  }

  const subject = extractField(summary, 'Subject');

  return {
    json: {
      callId: data.callId,
      meetingAccepted: meetingAccepted,
      childName: childName,
      parentName: parentName,
      phone: phone,
      email: email,
      timezone: timezone,
      appointmentDateTime: appointmentDateTime,
      childGrade: childGrade,
      subject: subject
    }
  };
});

