  const timezone = extractField(summary, 'Timezone');

  // Extract child info
  const childName = extractField(summary, 'Child Name');
  const childGradeRaw = extractField(summary, 'Grade');

  // Extract only the numeric value from grade
  let childGrade = null;
  if (childGradeRaw !== 'Not confirmed') {
    const gradeMatch = childGradeRaw.match(/\d+/);
    if (gradeMatch) {
      childGrade = parseInt(gradeMatch[0], 10);
    }
  }

  const subject = extractField(summary, 'Subject');

